UPDATE alevel_pdf_page
SET status = 0,
    update_time = #{updateTime}
WHERE alevel_pdf_page_id = #{pdfPageId}
  AND status = 1
  AND delete_flag = '1'

UPDATE alevel_pdf_page
SET status = 0,
    update_time = #{updateTime}
WHERE alevel_source_file_id = #{sourceFileId}
  AND status = 1
  AND delete_flag = '1'
